#!/usr/bin/env node
/**
 * pi-mind postinstall: wire the package into the host repo's .pi/ tree.
 *
 * Thin wrapper over the importable helper in ./init-lib.js (which is
 * plain ESM, ships next to this file in the bin/ directory, and does
 * NOT depend on dist/).
 *
 * This file must be runnable in a FRESH CLONE where the package's
 * `dist/` directory hasn't been built yet. The npm lifecycle order is
 * postinstall -> prepare, so at postinstall time `dist/lib/init.js`
 * does not exist. The fix: do not depend on it. Only depend on the
 * sibling `./init-lib.js` (generated by `npm run build`, and committed
 * to git so the first clone bootstraps without a build).
 *
 * Order of operations:
 *   1. Static `import` of node: built-ins (always present; can never
 *      fail at module load).
 *   2. Check PI_MIND_SKIP_INIT. If set, exit BEFORE the dynamic
 *      import. Critical: we use `await import()` for init-lib.js
 *      rather than a hoisted `import` statement, because ESM `import`
 *      is evaluated during module load -- before any top-level code
 *      runs. If the import target is missing, the SKIP short-circuit
 *      would never get a chance to fire. With dynamic import, the
 *      SKIP check runs first and exits cleanly even if init-lib.js is
 *      absent.
 *   3. Dynamic-import ./init-lib.js. Without it, the install crashes
 *      with a clear module-not-found error -- not a silent no-op.
 *   4. Resolve host root (INIT_CWD or pnpm-aware walk).
 *   5. Call runInit() and print the "ready" banner.
 */

import { fileURLToPath } from "node:url";
import { dirname, join, resolve } from "node:path";

if (process.env.PI_MIND_SKIP_INIT === "1") {
  console.log("[pi-mind] init skipped (PI_MIND_SKIP_INIT=1)");
  process.exit(0);
}

const { runInit, findHostRoot } = await import("./init-lib.js");

const __filename = fileURLToPath(import.meta.url);
const PKG_ROOT = resolve(dirname(__filename), "..");

// Locate the host project root. Preferred: $INIT_CWD (set by npm to the
// directory where npm was invoked). Fallback: walk up from PKG_ROOT
// looking for a node_modules ancestor that's NOT inside a pnpm cache.
const HOST_ROOT = findHostRoot(
  PKG_ROOT,
  process.env.INIT_CWD && resolve(process.env.INIT_CWD) !== PKG_ROOT
    ? resolve(process.env.INIT_CWD)
    : undefined,
);

if (!HOST_ROOT) {
  console.log("[pi-mind] not installed in a host project (dev mode), skipping init");
  process.exit(0);
}

console.log(`[pi-mind] initializing in ${HOST_ROOT}`);

const PI_MIND_DIR = process.env.PI_MIND_DIR || join(HOST_ROOT, ".pi-mind");

runInit({
  hostRoot: HOST_ROOT,
  pkgRoot: PKG_ROOT,
  piMindDir: PI_MIND_DIR,
  log: (line) => console.log(`[pi-mind] ${line}`),
  warn: (line) => console.warn(`[pi-mind] ${line}`),
});

console.log(`[pi-mind] ready. Run 'pi' in ${HOST_ROOT} to use the agent.`);
